package com.example.myapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity

class DeepLinkHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // This activity has no UI, it just dispatches the deep link

        val uri: Uri? = intent?.data

        if (uri != null) {
            handleDeepLink(uri)
        } else {
            // Fallback to MainActivity if no URI is provided (shouldn't happen for deep links)
            startActivity(Intent(this, MainActivity::class.java))
        }

        // Finish this activity so it doesn't stay on the back stack
        finish()
    }

    private fun handleDeepLink(uri: Uri) {
        val host = uri.host
        val pathSegments = uri.pathSegments

        when (host) {
            "profile" -> {
                if (pathSegments.isNotEmpty()) {
                    val profileId = pathSegments[0]
                    val intent = Intent(this, ProfileActivity::class.java).apply {
                        putExtra("profileId", profileId)
                    }
                    startActivity(intent)
                } else {
                    // Handle malformed profile link, e.g., myapp://profile
                    startActivity(Intent(this, MainActivity::class.java))
                }
            }
            "payment" -> {
                if (pathSegments.isNotEmpty() && pathSegments[0] == "confirm") {
                    val transactionId = uri.getQueryParameter("transactionId")
                    val intent = Intent(this, PaymentConfirmationActivity::class.java).apply {
                        transactionId?.let { putExtra("transactionId", it) }
                    }
                    startActivity(intent)
                } else {
                    // Handle malformed payment link, e.g., myapp://payment
                    startActivity(Intent(this, MainActivity::class.java))
                }
            }
            // Add more deep link routes here as needed
            else -> {
                // Default fallback for any other unknown host or root deep link myapp://
                startActivity(Intent(this, MainActivity::class.java))
            }
        }
    }
}

