ProfileActivity.kt

package com.example.myapp

import android.os.Bundle
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ProfileActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_profile)

        val profileId = intent.getStringExtra("profileId")
        val profileIdTextView: TextView = findViewById(R.id.profile_id_text)
        profileIdTextView.text = "Profile ID: ${profileId ?: "N/A"}"
    }
}

PaymentConfirmationActivity.kt

package com.example.myapp

import android.os.Bundle
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class PaymentConfirmationActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_payment_confirmation)

        val transactionId = intent.getStringExtra("transactionId")
        val transactionIdTextView: TextView = findViewById(R.id.transaction_id_text)

        if (transactionId != null) {
            transactionIdTextView.text = "Payment Confirmed for Transaction ID: $transactionId"
        } else {
            transactionIdTextView.text = "Payment Confirmation (No specific Transaction ID provided)"
        }
    }
}

